const query = $input.first().json.query || {};
const verifyToken = $env.META_VERIFY_TOKEN;

if (query['hub.mode'] === 'subscribe' && query['hub.verify_token'] === verifyToken) {
  return [{ json: { challenge: query['hub.challenge'], status: 200 } }];
}

return [{ json: { challenge: 'FORBIDDEN', status: 403 } }];

const body = $input.first().json.body;
const entry = body?.entry?.[0];
const changes = entry?.changes?.[0];
const value = changes?.value;
const message = value?.messages?.[0];
const hasStatuses = !!(value?.statuses);

const valid = !!message && message.type === 'text' && !hasStatuses;

return [{ json: { valid, body } }];

const body = $input.first().json.body;
const value = body.entry[0].changes[0].value;
const message = value.messages[0];
const contact = value.contacts?.[0];

return [{
  json: {
    telefono: message.from,
    mensaje: message.text.body,
    nombre_wa: contact?.profile?.name || null,
    message_id: message.id,
    timestamp: message.timestamp
  }
}];

const { telefono, nombre_wa } = $input.first().json;
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_KEY;

const headers = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

// Buscar lead existente
const searchRes = await fetch(
  `${supabaseUrl}/rest/v1/leads?telefono=eq.${encodeURIComponent(telefono)}&select=*&limit=1`,
  { headers }
);
const existingLeads = await searchRes.json();

let lead;
if (existingLeads.length > 0) {
  lead = existingLeads[0];
} else {
  // Crear nuevo lead
  const createRes = await fetch(`${supabaseUrl}/rest/v1/leads`, {
    method: 'POST',
    headers,
    body: JSON.stringify({
      telefono,
      nombre: nombre_wa,
      estado: 'nuevo'
    })
  });
  const created = await createRes.json();
  lead = created[0];
}

const msgData = $('Code Extraer Datos').first().json;

return [{
  json: {
    lead_id: lead.id,
    lead_nombre: lead.nombre || nombre_wa || null,
    lead_estado: lead.estado || 'nuevo',
    telefono: msgData.telefono,
    mensaje: msgData.mensaje,
    nombre_wa: msgData.nombre_wa,
    message_id: msgData.message_id
  }
}];

const input = $input.first().json;
const { lead_id, lead_nombre, lead_estado, telefono, mensaje, nombre_wa, message_id } = input;
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_KEY;

const headers = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

const histRes = await fetch(
  `${supabaseUrl}/rest/v1/conversaciones?lead_id=eq.${lead_id}&order=created_at.asc&limit=20&select=rol,mensaje`,
  { headers }
);
const historial = await histRes.json();

return [{
  json: {
    lead_id,
    lead_nombre,
    lead_estado,
    telefono,
    mensaje,
    nombre_wa,
    message_id,
    historial: Array.isArray(historial) ? historial : []
  }
}];

const claudeResponse = $input.first().json;
const prev = $('Code Construir Prompt Claude').first().json;

const respuesta = claudeResponse.content?.[0]?.text ||
  'En este momento estamos atendiendo tu mensaje 🧊 En un momento te respondemos. ¡Gracias por tu paciencia!';

let nuevo_estado = null;
const r = respuesta.toLowerCase();

if (r.includes('50378474733') || r.includes('bienvenido a la familia')) {
  nuevo_estado = 'cerrado';
} else if (r.includes('cuál es tu') || r.includes('en qué ciudad') || r.includes('cuéntame') || r.includes('cómo se llama') || r.includes('qué tipo de negocio')) {
  nuevo_estado = 'en_conversacion';
} else if (r.includes('miremos los números') || r.includes('granizados/día') || r.includes('se pagó sola')) {
  nuevo_estado = 'calificado';
}

return [{
  json: {
    respuesta,
    nuevo_estado,
    lead_id: prev.lead_id,
    lead_estado: prev.lead_estado,
    telefono: prev.telefono,
    mensaje_usuario: prev.mensaje_usuario,
    message_id: prev.message_id
  }
}];

const {
  respuesta, nuevo_estado, lead_id, lead_estado,
  telefono, mensaje_usuario, message_id
} = $input.first().json;

const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_KEY;

const headers = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

// Guardar mensaje del usuario
await fetch(`${supabaseUrl}/rest/v1/conversaciones`, {
  method: 'POST',
  headers,
  body: JSON.stringify({ lead_id, rol: 'user', mensaje: mensaje_usuario })
});

// Guardar respuesta del agente
await fetch(`${supabaseUrl}/rest/v1/conversaciones`, {
  method: 'POST',
  headers,
  body: JSON.stringify({ lead_id, rol: 'assistant', mensaje: respuesta })
});

// Actualizar estado del lead si cambió
if (nuevo_estado && nuevo_estado !== lead_estado) {
  await fetch(
    `${supabaseUrl}/rest/v1/leads?id=eq.${lead_id}`,
    {
      method: 'PATCH',
      headers: { ...headers, 'Prefer': 'return=minimal' },
      body: JSON.stringify({ estado: nuevo_estado, updated_at: new Date().toISOString() })
    }
  );
}

// Preparar body para WhatsApp
const waBody = JSON.stringify({
  messaging_product: 'whatsapp',
  recipient_type: 'individual',
  to: telefono,
  type: 'text',
  text: {
    preview_url: false,
    body: respuesta
  }
});

return [{ json: { waBody, telefono, respuesta } }];
